// MARK: - Wallet Service

final class WalletService {
    static let shared = WalletService()
    private init() {}

    private let keyTag = "com.example.wallet.ecdsa.p256.privatekey"

    enum WalletError: Error {
        case keyNotFound
        case keyCreationFailed
        case keyCopyFailed(OSStatus)
        case signFailed
        case unsupported
    }

    func loadOrCreateKey() throws -> SecKey {
        if let existing = try? loadPrivateKey() {
            return existing
        }
        return try createPrivateKey()
    }

    func getPublicKey() throws -> P256.Signing.PublicKey {
        let secKey = try loadOrCreateKey()
        guard let pubSec = SecKeyCopyPublicKey(secKey) else { throw WalletError.keyCopyFailed(errSecInternalError) }
        var error: Unmanaged<CFError>?
        guard let pubData = SecKeyCopyExternalRepresentation(pubSec, &error) as Data? else {
            throw (error?.takeRetainedValue() as Error?) ?? WalletError.keyCopyFailed(errSecInternalError)
        }
        // For P-256, external rep is ANSI X9.63 (0x04 || X || Y)
        return try P256.Signing.PublicKey(x963Representation: pubData)
    }

    func derivedAddressHex() -> String? {
        guard let pub = try? getPublicKey() else { return nil }
        // MVP "address": last 20 bytes of SHA256(pubkey x963)
        let h = SHA256.hash(data: pub.x963Representation)
        let d = Data(h)
        return d.suffix(20).hexString
    }

    struct SignedResult {
        let messageHash: Data
        let signatureDER: Data
    }

    func sign(data: Data) throws -> SignedResult {
        let key = try loadOrCreateKey()
        let hash = SHA256.hash(data: data)
        let hashData = Data(hash)

        var error: Unmanaged<CFError>?
        guard let sig = SecKeyCreateSignature(
            key,
            .ecdsaSignatureDigestX962SHA256,
            hashData as CFData,
            &error
        ) as Data? else {
            throw (error?.takeRetainedValue() as Error?) ?? WalletError.signFailed
        }
        return SignedResult(messageHash: hashData, signatureDER: sig)
    }

    private func loadPrivateKey() throws -> SecKey {
        let query: [String: Any] = [
            kSecClass as String: kSecClassKey,
            kSecAttrApplicationTag as String: keyTag.data(using: .utf8)!,
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecReturnRef as String: true
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        if status == errSecSuccess, let key = item as! SecKey? {
            return key
        }
        if status == errSecItemNotFound {
            throw WalletError.keyNotFound
        }
        throw WalletError.keyCopyFailed(status)
    }

    private func createPrivateKey() throws -> SecKey {
        let access: SecAccessControl
        if #available(iOS 11.3, *) {
            access = SecAccessControlCreateWithFlags(
                nil,
                kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
                [.privateKeyUsage],
                nil
            )!
        } else {
            access = SecAccessControlCreateWithFlags(
                nil,
                kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
                SecAccessControlCreateFlags(),
                nil
            )!
        }

        let attributes: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256,
            kSecAttrTokenID as String: kSecAttrTokenIDSecureEnclave, // if unavailable, will fail; fallback below
            kSecPrivateKeyAttrs as String: [
                kSecAttrIsPermanent as String: true,
                kSecAttrApplicationTag as String: keyTag.data(using: .utf8)!,
                kSecAttrAccessControl as String: access
            ]
        ]

        var error: Unmanaged<CFError>?
        if let key = SecKeyCreateRandomKey(attributes as CFDictionary, &error) {
            return key
        }

        // Fallback: Keychain software key (works on all iOS devices)
        let fallbackAttrs: [String: Any] = [
            kSecAttrKeyType as String: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits as String: 256,
            kSecPrivateKeyAttrs as String: [
                kSecAttrIsPermanent as String: true,
                kSecAttrApplicationTag as String: keyTag.data(using: .utf8)!,
                kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
            ]
        ]
        if let key = SecKeyCreateRandomKey(fallbackAttrs as CFDictionary, &error) {
            return key
        }

        throw (error?.takeRetainedValue() as Error?) ?? WalletError.keyCreationFailed
    }
}

// MARK: - Blockchain Communication (Generic JSON-RPC-like endpoint)

struct BroadcastRequest: Codable {
    let publicKeyHex: String
    let messageHex: String
    let signatureDERHex: String
}

final class BlockchainClient {
    struct RPCEnvelope<T: Codable>: Codable {
        let jsonrpc: String
        let id: Int
        let method: String
        let params: T
    }

    func broadcastSignedPayload(endpoint: URL, request: BroadcastRequest) async throws -> String {
        let env = RPCEnvelope(jsonrpc: "2.0", id: 1, method: "broadcastSignedPayload", params: request)
        let body = try JSONEncoder().encode(env)

        var urlRequest = URLRequest(url: endpoint)
        urlRequest.httpMethod = "POST"
        urlRequest.httpBody = body
        urlRequest.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let (data, response) = try await URLSession.shared.data(for: urlRequest)
        if let http = response as? HTTPURLResponse, !(200...299).contains(http.statusCode) {
            return "HTTP \(http.statusCode): \(String(data: data, encoding: .utf8) ?? "")"
        }
        return String(data: data, encoding: .utf8) ?? ""
    }
}

// MARK: - Utilities

extension Data {
    var hexString: String {
        map { String(format: "%02x", $0) }.joined()
    }

    init?(hex: String) {
        let s = hex.trimmingCharacters(in: .whitespacesAndNewlines)
        guard s.count % 2 == 0 else { return nil }
        var data = Data()
        data.reserveCapacity(s.count / 2)
        var idx = s.startIndex
        while idx < s.endIndex {
            let next = s.index(idx, offsetBy: 2)
            let byteStr = s[idx..<next]
            guard let b = UInt8(byteStr, radix: 16) else { return nil }
            data.append(b)
            idx = next
        }
        self = data
    }
}